public async Task PurchaseTicketsAsync(int eventId, int quantity)
{
    using var transaction = await _context.Database.BeginTransactionAsync();
    try
    {
        var targetEvent = await _context.Events.SingleOrDefaultAsync(e => e.Id == eventId);
        if (targetEvent == null) throw new InvalidOperationException("Event not found.");
        if (targetEvent.AvailableSeats < quantity) throw new InvalidOperationException("Not enough seats available.");

        targetEvent.AvailableSeats -= quantity;
        _context.Events.Update(targetEvent);
        await _context.SaveChangesAsync();

        await transaction.CommitAsync();
    }
    catch (DbUpdateConcurrencyException)
    {
        await transaction.RollbackAsync();
        throw;
    }
    catch
    {
        await transaction.RollbackAsync();
        throw;
    }
